import React, { useState, useEffect } from 'react';
import './contact.css';
import Header from '../Components/header';
import Footer from '../Components/Footer';
import {
  FaMapMarkerAlt,
  FaPhoneAlt,
  FaEnvelope,
  FaPaperPlane,
  FaCheckCircle,
} from 'react-icons/fa';
import AOS from 'aos';
import 'aos/dist/aos.css';

const ContactSection: React.FC = () => {
  useEffect(() => {
    AOS.init({ duration: 1000, once: true });
  }, []);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    message: '',
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);

  const handleChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const formUrl = 'https://docs.google.com/forms/d/e/1FAIpQLSdoSJv57tLdEFGNhvJKIvQe6vlIRknTGqCXnT21hjU8H1dSDg/formResponse';

    const data = new URLSearchParams();
    data.append('entry.466204223', formData.name);     // Name
    data.append('entry.32405555', formData.phone);      // Phone
    data.append('entry.2122071872', formData.email);    // Email
    data.append('entry.176904452', formData.message);   // Message
    data.append('entry.1591426887', window.location.pathname); // Page
    data.append('entry.688569624', 'bravo-roofing-lead');       // Campaign

    try {
      await fetch(formUrl, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: data.toString(),
      });

      setIsSubmitting(false);
      setSubmitSuccess(true);
      setFormData({ name: '', email: '', phone: '', message: '' });
      setTimeout(() => setSubmitSuccess(false), 5000);
    } catch (error) {
      console.error('Form submission error:', error);
      alert('Something went wrong. Please try again later.');
      setIsSubmitting(false);
    }
  };

  return (
    <div>
      <Header />
      <section className="hipo-contact-section" id="contact">
        <div className="hipo-contact-container">
          <div className="hipo-contact-header" data-aos="fade-up">
            <h2>Get In Touch With Us</h2>
            <p>
              Have questions or ready to start a project? Our team is here to help you achieve your goals.
            </p>
          </div>

          <div className="hipo-contact-content">
            <div className="hipo-contact-info" data-aos="fade-right">
              <div className="hipo-contact-item">
                <div className="hipo-contact-icon">
                  <FaMapMarkerAlt className="hipo-contact-icon-svg" />
                </div>
                <div className="hipo-contact-text">
                  <h3>Our Location</h3>
                  <p>
                    Boise, ID<br />
                    United States, Idaho
                  </p>
                </div>
              </div>

              <div className="hipo-contact-item">
                <div className="hipo-contact-icon">
                  <FaPhoneAlt className="hipo-contact-icon-svg" />
                </div>
                <div className="hipo-contact-text">
                  <h3>Phone Number</h3>
                  <p>
                    (208) 515-9425<br />
                    Mon-Fri: 9am - 6pm
                  </p>
                </div>
              </div>

              <div className="hipo-contact-item">
                <div className="hipo-contact-icon">
                  <FaEnvelope className="hipo-contact-icon-svg" />
                </div>
                <div className="hipo-contact-text">
                  <h3>Email Address</h3>
                  <p>bravoroofing208@gmail.com</p>
                </div>
              </div>
            </div>

            <div className="hipo-contact-form-container" data-aos="fade-left">
              <div className="hipo-contact-form">
                <h3>Send Us a Message</h3>
                <form onSubmit={handleSubmit}>
                  <div className="hipo-form-group">
                    <label htmlFor="name">Full Name</label>
                    <input
                      type="text"
                      id="name"
                      name="name"
                      value={formData.name}
                      onChange={handleChange}
                      placeholder="Enter your name"
                      required
                    />
                  </div>

                  <div className="hipo-form-group">
                    <label htmlFor="email">Email Address</label>
                    <input
                      type="email"
                      id="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      placeholder="Enter your email"
                      required
                    />
                  </div>

                  <div className="hipo-form-group">
                    <label htmlFor="phone">Phone Number</label>
                    <input
                      type="tel"
                      id="phone"
                      name="phone"
                      value={formData.phone}
                      onChange={handleChange}
                      placeholder="Enter your phone number"
                    />
                  </div>

                  <div className="hipo-form-group">
                    <label htmlFor="message">Your Message</label>
                    <textarea
                      id="message"
                      name="message"
                      value={formData.message}
                      onChange={handleChange}
                      placeholder="How can we help you?"
                      required
                    ></textarea>
                  </div>

                  <button
                    type="submit"
                    className="hipo-submit-btn"
                    disabled={isSubmitting}
                  >
                    {isSubmitting ? (
                      <>Sending...</>
                    ) : (
                      <>
                        <FaPaperPlane className="hipo-submit-icon" /> Send Message
                      </>
                    )}
                  </button>

                  {submitSuccess && (
                    <div className="hipo-success-message">
                      <FaCheckCircle className="hipo-success-icon" />
                      Thank you! We’ll get back to you shortly.
                    </div>
                  )}
                </form>
              </div>
            </div>
          </div>

          <div className="hipo-map-container" data-aos="zoom-in-up">
            <iframe
              src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d184620.4661670462!2d-116.57355284238314!3d43.696108354319676!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x54ae557c1c2f3c8f%3A0xcb0db6c9d964d0e!2sBravo%20Roofing!5e0!3m2!1sen!2s!4v1752786055752!5m2!1sen!2s"
              allowFullScreen
              loading="lazy"
              referrerPolicy="no-referrer-when-downgrade"
              title="Google Maps Location"
            ></iframe>
          </div>
        </div>
      </section>
      <Footer />
    </div>
  );
};

export default ContactSection;
